private final class APIHTTPByteStreamAccumulator {
    private let lock = NSLock()
    private let chunkSize: Int
    private var chunk = Data()
    private var closed = false

    init(chunkSize: Int) {
        self.chunkSize = chunkSize
        chunk.reserveCapacity(chunkSize)
    }

    func append(_ byte: UInt8) -> Data? {
        lock.lock()
        defer { lock.unlock() }
        if closed {
            return nil
        }
        chunk.append(byte)
        if chunk.count >= chunkSize {
            let data = chunk
            chunk.removeAll(keepingCapacity: true)
            return data
        }
        return nil
    }

    func flush() -> Data? {
        lock.lock()
        defer { lock.unlock() }
        if closed || chunk.isEmpty {
            return nil
        }
        let data = chunk
        chunk.removeAll(keepingCapacity: true)
        return data
    }

    func finish() -> Data? {
        lock.lock()
        defer { lock.unlock() }
        if closed {
            return nil
        }
        closed = true
        if chunk.isEmpty {
            return nil
        }
        let data = chunk
        chunk.removeAll(keepingCapacity: true)
        return data
    }

    func cancel() {
        lock.lock()
        closed = true
        chunk.removeAll(keepingCapacity: false)
        lock.unlock()
    }
}

